def verify_hmac_signature(payload_body: bytes, signature_header: str, secret: str) -> bool:
    """Verify the HMAC-SHA256 signature of the webhook payload."""
    if not signature_header or not secret:
        return False

    # Support multiple signature formats
    # Format: sha256=<hex_digest> (GitHub/Stripe style)
    if signature_header.startswith("sha256="):
        expected_signature = signature_header[7:]
    # Format: v1=<hex_digest> (some providers)
    elif "=" in signature_header:
        expected_signature = signature_header.split("=", 1)[1]
    else:
        expected_signature = signature_header

    computed_signature = hmac.new(
        secret.encode("utf-8"),
        payload_body,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(computed_signature, expected_signature)


def verify_stripe_signature(payload_body: bytes, signature_header: str, secret: str) -> bool:
    """Verify Stripe-specific webhook signature (t=timestamp,v1=signature format)."""
    if not signature_header or not secret:
        return False

    try:
        elements = dict(
            item.split("=", 1) for item in signature_header.split(",")
        )
        timestamp = elements.get("t", "")
        signature = elements.get("v1", "")

        if not timestamp or not signature:
            return False

        signed_payload = f"{timestamp}.".encode("utf-8") + payload_body
        expected_signature = hmac.new(
            secret.encode("utf-8"),
            signed_payload,
            hashlib.sha256
        ).hexdigest()

        return hmac.compare_digest(expected_signature, signature)
    except (ValueError, AttributeError):
        return False


def validate_ip(request) -> bool:
    """Validate the request comes from an allowed IP address."""
    if not ALLOWED_IPS or ALLOWED_IPS == [""]:
        # If no IP allowlist is configured, skip IP validation
        return True

    # Check X-Forwarded-For header (Cloud Functions behind load balancer)
    forwarded_for = request.headers.get("X-Forwarded-For", "")
    if forwarded_for:
        client_ip = forwarded_for.split(",")[0].strip()
    else:
        client_ip = request.remote_addr

    return client_ip in ALLOWED_IPS


def validate_request(request) -> tuple:
    """
    Validate the incoming webhook request.
    Returns (is_valid: bool, error_message: str, partner: str)
    """
    # Check HTTP method
    if request.method != "POST":
        return False, "Method not allowed. Only POST requests are accepted.", ""

    # Check Content-Type
    content_type = request.headers.get("Content-Type", "")
    if "application/json" not in content_type:
        return False, "Invalid Content-Type. Expected application/json.", ""

    # Validate IP allowlist
    if not validate_ip(request):
        logger.warning(f"Request from unauthorized IP: {request.remote_addr}")
        return False, "Unauthorized IP address.", ""

    # Determine partner from header or query parameter
    partner = (
        request.headers.get("X-Webhook-Partner", "")
        or request.args.get("partner", "")
    ).lower()

    if not partner:
        return False, "Missing partner identifier. Provide X-Webhook-Partner header or ?partner= query param.", ""

    if partner not in ALLOWED_PARTNERS:
        return False, f"Unknown partner: {partner}", ""

    # Get raw payload for signature verification
    payload_body = request.get_data()

    if not payload_body:
        return False, "Empty request body.", partner

    # Verify webhook signature based on partner
    if WEBHOOK_SECRET:
        signature_header = (
            request.headers.get("X-Webhook-Signature", "")
            or request.headers.get("X-Hub-Signature-256", "")
            or request.headers.get("Stripe-Signature", "")
            or request.headers.get("X-Signature", "")
        )

        if not signature_header:
            return False, "Missing webhook signature header.", partner

        if partner == "stripe":
            is_valid = verify_stripe_signature(payload_body, signature_header, WEBHOOK_SECRET)
        else:
            is_valid = verify_hmac_signature(payload_body, signature_header, WEBHOOK_SECRET)

        if not is_valid:
            logger.warning(f"Invalid signature from partner: {partner}")
            return False, "Invalid webhook signature.", partner

    # Validate JSON payload
    try:
        json.loads(payload_body)
    except json.JSONDecodeError:
        return False, "Invalid JSON payload.", partner

    return True, "", partner


